import okhttp3.OkHttpClient
import okhttp3.Request
import java.util.concurrent.TimeUnit

object HttpClient {
    private const val TIMEOUT = 10L // seconds

    fun getOkHttpClient(): OkHttpClient {
        return OkHttpClient.Builder()
            .connectTimeout(TIMEOUT, TimeUnit.SECONDS)
            .readTimeout(TIMEOUT, TimeUnit.SECONDS)
            .writeTimeout(TIMEOUT, TimeUnit.SECONDS)
            .build()
    }

    suspend fun sendRequest(url: String): String? {
        val client = getOkHttpClient()
        try {
            val request = Request.Builder().url(url).build()
            val response = client.newCall(request).execute()
            return response.body?.string()
        } catch (e: Exception) {
            println("Error sending request to $url")
            e.printStackTrace()
            return null
        }
    }

    suspend fun sendRequestWithParams(url: String, params: Map<String, String>): String? {
        val client = getOkHttpClient()
        try {
            val request = Request.Builder().url(url)
                .post(okhttp3.RequestBody.create(okhttp3.MediaType.get("application/json"), ""))
                .build()

            val body = okhttp3.FormBody.Builder()
            for ((key, value) in params) {
                body.add(key, value)
            }
            request.body = body.build()

            val response = client.newCall(request).execute()
            return response.body?.string()
        } catch (e: Exception) {
            println("Error sending request to $url")
            e.printStackTrace()
            return null
        }
    }
}